#[rustler::nif]
pub fn add_cors_headers(response: Option<String>, origin: String, cors_config: Option<String>) -> () {
    let response_core: Option<spikard::Response> = response
        .map(|s| serde_json::from_str::<spikard::Response>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let cors_config_core: Option<spikard::CorsConfig> = cors_config
        .map(|s| serde_json::from_str::<spikard::CorsConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    spikard_http::cors::add_cors_headers(
        response_core.as_ref().unwrap_or(&Default::default()),
        &origin,
        cors_config_core.as_ref().unwrap_or(&Default::default()),
    )
}

