#[allow(dead_code)]
fn graph_q_l_error_to_rustler_err(e: spikard_graphql::error::GraphQLError) -> String {
    e.to_string()
}

/// Convert a `spikard_graphql::schema::SchemaError` error to a Rustler error string.
